"""
Belief-state replay: reconstruct what the store would expose as of a past cutoff.

Honesty constraints:
- Embedding vectors and cluster IDs reflect the *current* encoder and graph; replay
  filters *which* claims/conclusions participate by effective time, not historical weights.
- Use ``embedding_model_version`` rows to surface which encoder was pinned when; if the
  table only has the auto-seed row, callers should warn that encoder drift is unmodeled.
"""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from datetime import date, datetime, time, timezone
from typing import Any, Iterable, Optional

from noosphere.models import Artifact, Claim, Conclusion
from noosphere.observability import get_logger
from noosphere.store import Store, StoredEmbeddingModelVersion

logger = get_logger(__name__)


def parse_cutoff_date(s: str) -> date:
    return date.fromisoformat(s.strip())


def cutoff_datetime_inclusive_utc(d: date) -> datetime:
    """Inclusive end-of-calendar-day UTC for ``effective_at <= cutoff`` checks."""
    return datetime(d.year, d.month, d.day, 23, 59, 59, tzinfo=timezone.utc)


def _ensure_utc(dt: datetime) -> datetime:
    if dt.tzinfo is None:
        return dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc)


def effective_datetime_for_artifact(art: Artifact) -> tuple[datetime, bool]:
    if art.effective_at is not None:
        return _ensure_utc(art.effective_at), art.effective_at_inferred
    if art.source_date:
        d = art.source_date
        return (
            datetime(d.year, d.month, d.day, 23, 59, 59, tzinfo=timezone.utc),
            False,
        )
    return _ensure_utc(art.created_at), True


def effective_datetime_for_claim(store: Store, c: Claim) -> tuple[datetime, bool]:
    if c.effective_at is not None:
        return _ensure_utc(c.effective_at), c.effective_at_inferred
    if c.source_id:
        art = store.get_artifact(c.source_id)
        if art is not None:
            return effective_datetime_for_artifact(art)
    return datetime.combine(c.episode_date, time.max, tzinfo=timezone.utc), True


def is_active_superseded(superseded_at: Optional[datetime], cutoff: datetime) -> bool:
    if superseded_at is None:
        return True
    return _ensure_utc(superseded_at) > cutoff


def claim_visible_as_of(store: Store, c: Claim, cutoff: datetime) -> bool:
    if not is_active_superseded(c.superseded_at, cutoff):
        return False
    eff, _ = effective_datetime_for_claim(store, c)
    return eff <= cutoff


def artifact_visible_as_of(store: Store, artifact_id: str, cutoff: datetime) -> bool:
    if not artifact_id:
        return True
    art = store.get_artifact(artifact_id)
    if art is None:
        return True
    if not is_active_superseded(art.superseded_at, cutoff):
        return False
    eff, _ = effective_datetime_for_artifact(art)
    return eff <= cutoff


def filter_claims_as_of(
    store: Store,
    claims: dict[str, Claim],
    as_of: date,
    *,
    exclude_artifact_ids: Optional[set[str]] = None,
) -> dict[str, Claim]:
    cutoff = cutoff_datetime_inclusive_utc(as_of)
    ex = exclude_artifact_ids or set()
    out: dict[str, Claim] = {}
    for cid, c in claims.items():
        if c.source_id and c.source_id in ex:
            continue
        if not claim_visible_as_of(store, c, cutoff):
            continue
        if c.source_id and not artifact_visible_as_of(store, c.source_id, cutoff):
            continue
        out[cid] = c
    return out


def list_conclusions_replay_consistent(store: Store, as_of: date) -> list[Conclusion]:
    """
    Conclusions that could have been asserted by ``as_of``: synthesized no later than the
    cutoff and whose stored evidence claims are all visible on that cutoff.
    """
    cutoff = cutoff_datetime_inclusive_utc(as_of)
    out: list[Conclusion] = []
    for con in store.list_conclusions():
        if con.superseded_at is not None and _ensure_utc(con.superseded_at) <= cutoff:
            continue
        if _ensure_utc(con.created_at) > cutoff:
            continue
        ok = True
        for eid in con.evidence_chain_claim_ids:
            cl = store.get_claim(eid)
            if cl is None or not claim_visible_as_of(store, cl, cutoff):
                ok = False
                break
        if ok:
            out.append(con)
    return out


def embedding_model_disclaimer(store: Store, as_of: date) -> list[str]:
    cutoff = cutoff_datetime_inclusive_utc(as_of)
    rows: list[tuple[datetime, str]] = []
    with store.session() as s:
        from sqlmodel import select

        for r in s.exec(select(StoredEmbeddingModelVersion).order_by(StoredEmbeddingModelVersion.effective_from)).all():
            eff_r = r.effective_from
            if eff_r.tzinfo is None:
                eff_r = eff_r.replace(tzinfo=timezone.utc)
            rows.append((eff_r, r.model_name))
    warns: list[str] = []
    if not rows:
        warns.append("No embedding_model_version rows; encoder history is unmodeled.")
        return warns
    best: Optional[tuple[datetime, str]] = None
    for eff, name in rows:
        if eff <= cutoff:
            best = (eff, name)
    if best is None:
        warns.append(
            f"No embedding_model_version effective on or before {as_of.isoformat()}; "
            f"using earliest recorded ({rows[0][1]} from {rows[0][0].date().isoformat()})."
        )
    elif len(rows) == 1:
        warns.append(
            "Only one embedding_model_version row (auto-seed). Encoder drift vs historical "
            "replay is not fully tracked; vectors in the store reflect the current encoder run."
        )
    return warns


@dataclass
class BeliefDiff:
    """Structured diff between two replay cutoffs (conclusion ids)."""

    date_a: date
    date_b: date
    conclusions_only_in_b: list[str] = field(default_factory=list)
    conclusions_only_in_a: list[str] = field(default_factory=list)
    claims_gained_visibility_in_b: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)


def diff_belief_cutoffs(store: Store, date_a: date, date_b: date) -> BeliefDiff:
    if date_a > date_b:
        date_a, date_b = date_b, date_a
    sa = {c.id for c in list_conclusions_replay_consistent(store, date_a)}
    sb = {c.id for c in list_conclusions_replay_consistent(store, date_b)}
    diff = BeliefDiff(date_a=date_a, date_b=date_b)
    diff.conclusions_only_in_b = sorted(sb - sa)
    diff.conclusions_only_in_a = sorted(sa - sb)
    ca = cutoff_datetime_inclusive_utc(date_a)
    cb = cutoff_datetime_inclusive_utc(date_b)
    for cid in store.list_claim_ids():
        cl = store.get_claim(cid)
        if cl is None:
            continue
        va = claim_visible_as_of(store, cl, ca)
        vb = claim_visible_as_of(store, cl, cb)
        if not va and vb:
            diff.claims_gained_visibility_in_b.append(cid)
    diff.warnings.extend(embedding_model_disclaimer(store, date_b))
    return diff


def diff_structured_json(store: Store, date_a: date, date_b: date) -> dict[str, Any]:
    d = diff_belief_cutoffs(store, date_a, date_b)
    return {
        "date_a": d.date_a.isoformat(),
        "date_b": d.date_b.isoformat(),
        "conclusions_new_or_visible_by_b": d.conclusions_only_in_b,
        "conclusions_visible_by_a_not_b": d.conclusions_only_in_a,
        "claims_first_visible_by_b": d.claims_gained_visibility_in_b[:200],
        "warnings": d.warnings,
    }


def narrative_from_diff(
    store: Store,
    date_a: date,
    date_b: date,
    *,
    llm: Any | None = None,
) -> str:
    """
    Short narrative grounded in ``diff_structured_json``. Uses LLM when provided;
    otherwise a deterministic template.
    """
    payload = diff_structured_json(store, date_a, date_b)
    added = payload["conclusions_new_or_visible_by_b"]
    lost = payload["conclusions_visible_by_a_not_b"]
    claims = payload["claims_first_visible_by_b"]
    arts: set[str] = set()
    for cid in claims[:40]:
        cl = store.get_claim(cid)
        if cl and cl.source_id:
            arts.add(cl.source_id)
    art_meta = []
    for aid in sorted(arts)[:12]:
        a = store.get_artifact(aid)
        if a:
            art_meta.append({"id": aid, "title": a.title, "uri": a.uri})
    if llm is not None:
        try:
            prompt = (
                "Write 2–4 sentences summarizing intellectual change between two dates for a firm. "
                "You MUST only use the JSON facts below; cite artifact titles when present.\n"
                + json.dumps({**payload, "pivotal_artifacts": art_meta}, indent=2)
            )
            out = llm.complete(
                system="You write precise, grounded summaries. Never invent artifacts or claims.",
                user=prompt,
                max_tokens=400,
            )
            if isinstance(out, str) and out.strip():
                return out.strip()
        except Exception as e:  # pragma: no cover
            logger.warning("replay_narrative_llm_failed", error=str(e))
    lines = [
        f"Between {date_a.isoformat()} and {date_b.isoformat()}, the replay-consistent conclusion set "
        f"gained {len(added)} id(s) and lost {len(lost)} relative to the earlier cutoff.",
    ]
    if art_meta:
        titles = ", ".join(m["title"] or m["id"] for m in art_meta[:5])
        lines.append(f"Pivotal newly-visible evidence appears tied to artifacts: {titles}.")
    if payload["warnings"]:
        lines.append("Imperfections: " + " ".join(payload["warnings"]))
    return " ".join(lines)


def run_counterfactual_preview(
    orch: Any,
    *,
    exclude_artifact_ids: set[str],
    as_of: date,
) -> tuple[list[Conclusion], list[str]]:
    """Dry-run synthesis while excluding one or more artifact ids (claims sourced there dropped)."""
    claims = filter_claims_as_of(
        orch.store,
        dict(orch.graph.claims),
        as_of,
        exclude_artifact_ids=exclude_artifact_ids,
    )
    warns = embedding_model_disclaimer(orch.store, as_of)
    from noosphere.synthesis import run_synthesis_pipeline

    res = run_synthesis_pipeline(orch, store=orch.store, claims_by_id=claims, dry_run=True)
    return list(res.preview_conclusions), warns


def run_synthesis_as_of_preview(orch: Any, as_of: date) -> tuple[list[Conclusion], list[str]]:
    """
    Dry-run synthesis assembly using claims visible as of ``as_of`` (graph + SQL artifact filter).

    Returns (preview conclusions, warnings).
    """
    from noosphere.synthesis import run_synthesis_pipeline

    claims = filter_claims_as_of(orch.store, dict(orch.graph.claims), as_of)
    warns = embedding_model_disclaimer(orch.store, as_of)
    res = run_synthesis_pipeline(orch, store=orch.store, claims_by_id=claims, dry_run=True)
    return list(res.preview_conclusions), warns

"""Counterfactual runner: grades each method's predictive accuracy on held-out temporal slices."""

from __future__ import annotations

import logging
from datetime import datetime, timedelta, timezone
from typing import Any, Callable, Optional
from unittest.mock import patch
from uuid import uuid4

from noosphere.models import (
    CalibrationMetrics,
    CounterfactualEvalRun,
    MethodRef,
    Outcome,
    OutcomeKind,
    TemporalCut,
)
from noosphere.evaluation.outcomes import ResolutionResult, resolve
from noosphere.evaluation.metrics import compute_metrics_for_kind
from noosphere.evaluation.slicer import CorpusSlicer

logger = logging.getLogger(__name__)


class CounterfactualRunner:
    """Run methods against held-out temporal slices and grade predictions."""

    def __init__(
        self,
        store: Any,
        method_fn: Callable,
        method_ref: MethodRef,
        *,
        prediction_extractor: Optional[Callable] = None,
    ) -> None:
        self._store = store
        self._method_fn = method_fn
        self._method_ref = method_ref
        self._prediction_extractor = prediction_extractor or _default_extractor

    def run(
        self,
        window_start: datetime,
        window_end: datetime,
        cadence: timedelta,
        *,
        cuts: Optional[list[TemporalCut]] = None,
    ) -> CounterfactualEvalRun:
        run_id = f"cf-{uuid4().hex[:16]}"

        if cuts is None:
            cuts = self._generate_cuts(window_start, window_end, cadence)

        all_results: list[ResolutionResult] = []
        prediction_refs: list[str] = []
        total_by_kind: dict[OutcomeKind, int] = {}

        for cut in cuts:
            slicer = CorpusSlicer(self._store, cut)
            for outcome in cut.outcomes:
                total_by_kind[outcome.kind] = total_by_kind.get(outcome.kind, 0) + 1
                try:
                    with _block_network():
                        prediction = self._method_fn(slicer)
                except Exception:
                    logger.warning(
                        "Method %s failed on cut %s", self._method_ref.name, cut.cut_id,
                        exc_info=True,
                    )
                    continue

                extracted = self._prediction_extractor(prediction, outcome)
                if extracted is None:
                    continue

                try:
                    result = resolve(outcome, extracted)
                    all_results.append(result)
                    prediction_refs.append(
                        f"{cut.cut_id}:{outcome.outcome_id}"
                    )
                except Exception:
                    logger.warning(
                        "Resolution failed for outcome %s", outcome.outcome_id,
                        exc_info=True,
                    )

        metrics = self._aggregate_metrics(all_results, total_by_kind)

        return CounterfactualEvalRun(
            run_id=run_id,
            method_ref=self._method_ref,
            cut_id=cuts[0].cut_id if cuts else "",
            metrics=metrics,
            prediction_refs=prediction_refs,
            created_at=datetime.now(timezone.utc),
        )

    def _generate_cuts(
        self,
        window_start: datetime,
        window_end: datetime,
        cadence: timedelta,
    ) -> list[TemporalCut]:
        from noosphere.models import CorpusSelector

        cuts: list[TemporalCut] = []
        t = window_start
        while t <= window_end:
            outcomes = self._store.list_outcomes_for_cut(f"auto-{t.isoformat()}")
            cut = TemporalCut(
                cut_id=f"auto-{t.isoformat()}",
                as_of=t,
                corpus_slice=CorpusSelector(as_of=t),
                embargoed=CorpusSelector(as_of=t),
                embedding_version_pin="default",
                outcomes=outcomes if outcomes else [],
            )
            cuts.append(cut)
            t += cadence
        return cuts

    def _aggregate_metrics(
        self,
        results: list[ResolutionResult],
        total_by_kind: dict[OutcomeKind, int],
    ) -> CalibrationMetrics:
        if not results:
            return CalibrationMetrics(
                brier=0.0, log_loss=0.0, ece=0.0,
                reliability_bins=[], resolution=0.0, coverage=0.0,
            )
        present_kinds = {r.kind for r in results}
        if len(present_kinds) == 1:
            kind = next(iter(present_kinds))
            return compute_metrics_for_kind(
                results, kind, total_by_kind.get(kind, len(results))
            )
        first_kind = next(iter(sorted(present_kinds, key=lambda k: k.value)))
        return compute_metrics_for_kind(
            results, first_kind, total_by_kind.get(first_kind, len(results))
        )


def _default_extractor(prediction: Any, outcome: Outcome) -> Any:
    if isinstance(prediction, dict):
        return prediction.get("prediction", prediction.get("value", prediction))
    return prediction


class _block_network:
    """Context manager that patches socket to prevent network access."""

    def __enter__(self):
        import socket
        self._orig_connect = socket.socket.connect

        def _blocked(*args, **kwargs):
            raise RuntimeError("Network access blocked during counterfactual run")

        self._patch = patch.object(socket.socket, "connect", _blocked)
        self._patch.start()
        return self

    def __exit__(self, *exc):
        self._patch.stop()

from __future__ import annotations

from typing import TYPE_CHECKING, Callable

from noosphere.models import CascadeEdgeRelation, Method

if TYPE_CHECKING:
    from noosphere.methods.domain_bounds import DomainBound


class MethodCollisionError(Exception):
    pass


class MethodNotFoundError(Exception):
    pass


def _parse_semver(version: str) -> tuple[int, ...]:
    parts: list[int] = []
    for p in version.split("."):
        try:
            parts.append(int(p))
        except ValueError:
            parts.append(0)
    return tuple(parts)


class MethodRegistry:
    def __init__(self) -> None:
        self._specs: dict[tuple[str, str], Method] = {}
        self._fns: dict[tuple[str, str], Callable] = {}
        self._emits_edges: dict[str, list[CascadeEdgeRelation]] = {}
        # name -> list of dependency method names (composition DAG).
        # Keyed on bare name because the DAG is about method identity,
        # not about a particular pinned version.
        self._depends_on: dict[str, list[str]] = {}
        # name -> declarative DomainBound. Side-table rather than a field
        # on Method because Method is `extra="forbid"` + `frozen=True` and
        # we want bounds to be re-curatable without re-publishing the
        # method spec. See noosphere/methods/domain_bounds.py.
        self._domain_bounds: dict[str, "DomainBound"] = {}

    def register(self, spec: Method, fn: Callable) -> None:
        key = (spec.name, spec.version)
        if key in self._specs:
            raise MethodCollisionError(
                f"Method {spec.name} v{spec.version} already registered"
            )
        self._specs[key] = spec
        self._fns[key] = fn

    def set_emits_edges(
        self, method_id: str, edges: list[CascadeEdgeRelation]
    ) -> None:
        self._emits_edges[method_id] = list(edges)

    def get_emits_edges(self, method_id: str) -> list[CascadeEdgeRelation]:
        return self._emits_edges.get(method_id, [])

    # ── composition DAG side table ────────────────────────────────────

    def set_depends_on(self, name: str, deps: list[str]) -> None:
        self._depends_on[name] = list(deps)

    def get_depends_on(self, name: str) -> list[str]:
        return list(self._depends_on.get(name, []))

    def iter_depends_on(self):
        for name, deps in self._depends_on.items():
            yield name, list(deps)

    # ── domain bounds side table ──────────────────────────────────────

    def set_domain_bound(self, name: str, bound: "DomainBound") -> None:
        self._domain_bounds[name] = bound

    def get_domain_bound(self, name: str) -> "DomainBound | None":
        return self._domain_bounds.get(name)

    def iter_domain_bounds(self):
        for name, bound in self._domain_bounds.items():
            yield name, bound

    def known_method_names(self) -> set[str]:
        return {n for (n, _v) in self._specs.keys()}

    def get(
        self,
        name: str,
        version: str = "latest",
        include_retired: bool = False,
    ) -> tuple[Method, Callable]:
        if version != "latest":
            key = (name, version)
            if key not in self._specs:
                raise MethodNotFoundError(
                    f"Method {name} v{version} not found"
                )
            spec = self._specs[key]
            if spec.status == "retired" and not include_retired:
                raise MethodNotFoundError(
                    f"Method {name} v{version} is retired"
                )
            return spec, self._fns[key]

        candidates: list[tuple[str, Method]] = []
        for (n, v), spec in self._specs.items():
            if n != name:
                continue
            if spec.status == "retired" and not include_retired:
                continue
            candidates.append((v, spec))

        if not candidates:
            raise MethodNotFoundError(f"No active method found for {name}")

        candidates.sort(key=lambda x: _parse_semver(x[0]), reverse=True)
        best_version = candidates[0][0]
        return self._specs[(name, best_version)], self._fns[(name, best_version)]

    def list(self, status_filter: str | None = None) -> list[Method]:
        specs = list(self._specs.values())
        if status_filter is not None:
            specs = [s for s in specs if s.status == status_filter]
        return specs


REGISTRY = MethodRegistry()

"""CLI commands for the Method Registry subsystem."""

from __future__ import annotations

import json
from datetime import datetime, timezone
from typing import Optional

import click
from rich.console import Console
from rich.table import Table

console = Console()


def _get_store():
    from noosphere.cli import get_orchestrator
    return get_orchestrator(None).store


def _render(obj, as_json: bool) -> None:
    if as_json:
        click.echo(json.dumps(obj, indent=2, default=str))


@click.group("methods")
def cli() -> None:
    """Method registry: list, inspect, run, and diff registered methods."""


@cli.command("list")
@click.option("--status", "status_filter", type=str, default=None,
              help="Filter by status (experimental, active, deprecated, retired)")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def list_methods(status_filter: Optional[str], as_json: bool) -> None:
    """List all registered methods."""
    from noosphere.methods import REGISTRY

    methods = REGISTRY.list(status_filter=status_filter)
    if as_json:
        _render([{"name": m.name, "version": m.version, "status": m.status,
                  "type": m.method_type.value, "description": m.description}
                 for m in methods], True)
        return
    if not methods:
        console.print("[yellow]No methods registered.[/yellow]")
        return
    table = Table(title="Registered Methods", show_header=True)
    table.add_column("Name", style="cyan")
    table.add_column("Version")
    table.add_column("Status")
    table.add_column("Type")
    table.add_column("Description", max_width=50)
    for m in methods:
        table.add_row(m.name, m.version, m.status, m.method_type.value,
                      m.description[:50])
    console.print(table)


@cli.command("show")
@click.argument("ref")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def show_method(ref: str, as_json: bool) -> None:
    """Show details of a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    method, _fn = REGISTRY.get(name, version=version)
    if as_json:
        _render(method.model_dump(), True)
        return
    table = Table(title=f"Method: {method.name}@{method.version}", show_header=False)
    for field in ("method_id", "name", "version", "method_type", "status",
                  "owner", "description", "rationale"):
        val = getattr(method, field)
        table.add_row(field, str(val) if not hasattr(val, "value") else val.value)
    table.add_row("preconditions", ", ".join(method.preconditions) or "—")
    table.add_row("postconditions", ", ".join(method.postconditions) or "—")
    console.print(table)

import type { Metadata } from "next";
import Link from "next/link";

import CalibrationPlot from "@/components/CalibrationPlot";
import PublicHeader from "@/components/PublicHeader";
import { getFounder } from "@/lib/auth";
import {
  type BrierWindow,
  type CalibrationFilter,
  type DecileEntry,
  type PublicCalibrationManifest,
  loadPublicCalibrationManifest,
} from "@/lib/calibrationData";

export const metadata: Metadata = {
  title: "Calibration Scorecard",
  description:
    "Theseus's published opinions and forecasts, scored against realized outcomes. Aggregate Brier, calibration plot, top and bottom calls, with a hash of the resolution set so the numbers can be audited.",
  openGraph: {
    title: "Theseus Calibration Scorecard",
    description:
      "How Theseus's forecasts have actually fared. Brier scores, calibration plot, best and worst calls, no cherry-picking.",
    type: "website",
  },
};

export const dynamic = "force-dynamic";

type SearchParams = {
  domain?: string;
  method?: string;
  version?: string;
};

export default async function CalibrationPage({
  searchParams,
}: {
  searchParams?: Promise<SearchParams> | SearchParams;
}) {
  const founder = await getFounder();
  const params = (await Promise.resolve(searchParams)) ?? {};
  const filter: CalibrationFilter = {
    domain: params.domain ?? null,
    methodName: params.method ?? null,
    methodVersion: params.version ?? null,
  };
  const manifest = await loadPublicCalibrationManifest(filter);

  return (
    <>
      <PublicHeader authed={Boolean(founder)} />
      <main className="public-container public-calibration-page" style={{ padding: "2rem 1.5rem" }}>
        <Hero manifest={manifest} />
        <Disclaimer manifest={manifest} />
        <Filters manifest={manifest} active={filter} />
        <PlotSection manifest={manifest} />
        <BrierWindows windows={manifest.aggregateBrier} />
        <Honesty manifest={manifest} />
        <Deciles
          best={manifest.decileBest}
          worst={manifest.decileWorst}
        />
        <Methods manifest={manifest} active={filter} />
        <ManifestPointer />
      </main>
    </>
  );
}

function Hero({ manifest }: { manifest: PublicCalibrationManifest }) {
  const overall = manifest.aggregateBrier.find((w) => w.label === "all-time");
  return (
    <section style={{ marginBottom: "2rem" }} aria-labelledby="calibration-hero-title">
      <h1 id="calibration-hero-title" className="public-title" style={{ fontSize: "2rem" }}>
        Calibration scorecard
      </h1>
      <p className="public-lede" style={{ marginTop: "0.5rem" }}>
        How Theseus's published forecasts have actually fared. Lower Brier
        is better; a well-calibrated firm tracks the dashed diagonal in
        the plot below.
      </p>
      <p
        style={{
          marginTop: "1rem",
          fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
          fontSize: "0.78rem",
          color: "#5a5247",
        }}
      >
        n_resolved={manifest.counts.resolvedBinary} · all-time Brier=
        {overall?.meanBrier !== null && overall?.meanBrier !== undefined ? overall.meanBrier.toFixed(3) : "—"} · withdrawn rate=
        {manifest.withdrawnRate !== null ? `${(manifest.withdrawnRate * 100).toFixed(1)}%` : "—"}
      </p>
    </section>
  );
}

function Disclaimer({ manifest }: { manifest: PublicCalibrationManifest }) {
  return (
    <section
      style={{
        border: "1px solid #d4a017",
        background: "#fffbeb",
        padding: "0.9rem 1rem",
        marginBottom: "1.5rem",
        fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
        fontSize: "0.78rem",
      }}
      aria-labelledby="cherry-pick-label"
    >
      <strong id="cherry-pick-label" style={{ display: "block", marginBottom: "0.4rem" }}>
        No cherry-picking
      </strong>
      <p style={{ margin: 0 }}>
        The metrics on this page cover every resolved forecast Theseus has
        published — not a curated subset. The SHA-256 hash below pins the
        exact resolution set used: re-derive it from the public manifest
        to verify nothing was dropped.
      </p>
      <p style={{ marginTop: "0.5rem", marginBottom: 0 }}>
        resolution_set_hash:{" "}
        <code style={{ wordBreak: "break-all" }}>{manifest.resolutionSetHash || "—"}</code>
      </p>
      <p style={{ marginTop: "0.4rem", marginBottom: 0, color: "#5a5247" }}>
        published_at: {manifest.generatedAt} · source: {manifest.source} · schema_v=
        {manifest.schemaVersion}
      </p>
    </section>
  );
}

function Filters({
  manifest,
  active,
}: {
  manifest: PublicCalibrationManifest;
  active: CalibrationFilter;
}) {
  const hasFilter = Boolean(active.domain || active.methodName || active.methodVersion);
  return (
    <section style={{ marginBottom: "1.5rem" }} aria-labelledby="filters-title">
      <h2 id="filters-title" style={{ fontSize: "0.92rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
        Filter
      </h2>
      <form
        method="get"
        action="/calibration"
        style={{
          display: "flex",
          flexWrap: "wrap",
          gap: "0.75rem",
          alignItems: "flex-end",
          marginTop: "0.5rem",
        }}
      >
        <label style={{ fontSize: "0.78rem" }}>
          Domain
          <select
            name="domain"
            defaultValue={active.domain ?? ""}
            style={{ display: "block", marginTop: "0.25rem", padding: "0.35rem 0.5rem", minWidth: "12rem" }}
          >
            <option value="">All domains</option>
            {manifest.domains.map((d) => (
              <option key={d} value={d}>
                {d}
              </option>
            ))}
          </select>
        </label>
        <label style={{ fontSize: "0.78rem" }}>
          Method
          <select
            name="method"
            defaultValue={active.methodName ?? ""}
            style={{ display: "block", marginTop: "0.25rem", padding: "0.35rem 0.5rem", minWidth: "16rem" }}
          >
            <option value="">All methods</option>
            {manifest.methods.map((m) => (
              <option key={`${m.name}@${m.version}`} value={m.name}>
                {m.name} (n={m.n})
              </option>
            ))}
          </select>
        </label>
        <input type="hidden" name="version" value={active.methodVersion ?? ""} />
        <button
          type="submit"
          style={{
            padding: "0.45rem 1rem",
            border: "1px solid #d4a017",
            background: "#fffdf7",
            color: "#7a5b0d",
            fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
            fontSize: "0.7rem",
            letterSpacing: "0.18em",
            textTransform: "uppercase",
          }}
        >
          Apply
        </button>
        {hasFilter ? (
          <Link
            href="/calibration"
            style={{ fontSize: "0.78rem", color: "#5a5247", textDecoration: "underline" }}
          >
            Clear
          </Link>
        ) : null}
      </form>
    </section>
  );
}

function PlotSection({ manifest }: { manifest: PublicCalibrationManifest }) {
  return (
    <section
      style={{
        display: "grid",
        gridTemplateColumns: "minmax(0, 1fr) minmax(0, 1.1fr)",
        gap: "1.5rem",
        marginBottom: "1.75rem",
      }}
      aria-labelledby="plot-title"
    >
      <div>
        <h2 id="plot-title" style={{ fontSize: "0.92rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
          Calibration plot
        </h2>
        <CalibrationPlot
          bins={manifest.calibrationCurve}
          sparseThreshold={manifest.sparseBinThreshold || 5}
        />
      </div>
      <div>
        <h2 style={{ fontSize: "0.92rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
          Slope
        </h2>
        <p style={{ fontSize: "0.85rem", marginTop: "0.5rem" }}>
          OLS slope of outcome ~ probability. A perfectly calibrated firm
          has slope ≈ 1.0; below 1 means under-discrimination, above 1
          means over-discrimination. Bootstrap CI at the published level.
        </p>
        <ul
          style={{
            listStyle: "none",
            padding: 0,
            marginTop: "0.5rem",
            fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
            fontSize: "0.82rem",
          }}
        >
          <li>slope = {fmt(manifest.calibrationSlope.slope)}</li>
          <li>
            ci = [{fmt(manifest.calibrationSlope.ciLow)}, {fmt(manifest.calibrationSlope.ciHigh)}]
          </li>
          <li>n = {manifest.calibrationSlope.sampleSize}</li>
        </ul>
        {manifest.continuousQuadraticLoss !== null ? (
          <p style={{ marginTop: "1rem", fontSize: "0.8rem", color: "#5a5247" }}>
            Continuous-market forecasts are scored separately as{" "}
            <code>{manifest.continuousMetricName}</code>:{" "}
            {fmt(manifest.continuousQuadraticLoss)}. Not folded into the
            binary Brier above.
          </p>
        ) : null}
      </div>
    </section>
  );
}

function BrierWindows({ windows }: { windows: BrierWindow[] }) {
  return (
    <section style={{ marginBottom: "2rem" }} aria-labelledby="windows-title">
      <h2 id="windows-title" style={{ fontSize: "0.92rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
        Aggregate Brier — rolling windows
      </h2>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))",
          gap: "0.75rem",
          marginTop: "0.5rem",
        }}
      >
        {windows.map((w) => (
          <div
            key={w.label}
            style={{
              border: "1px solid #d8d4cb",
              padding: "0.7rem 0.85rem",
              background: "#fffdf7",
            }}
          >
            <div style={{ fontSize: "0.7rem", letterSpacing: "0.15em", textTransform: "uppercase", color: "#7a6d55" }}>
              {w.label}
            </div>
            <div
              style={{
                fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
                fontSize: "1.05rem",
                marginTop: "0.25rem",
              }}
            >
              {fmt(w.meanBrier)}
            </div>
            <div style={{ fontSize: "0.72rem", color: "#7a6d55", marginTop: "0.2rem" }}>
              n = {w.n} · log loss = {fmt(w.meanLogLoss)}
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}

function Honesty({ manifest }: { manifest: PublicCalibrationManifest }) {
  return (
    <section style={{ marginBottom: "2rem" }} aria-labelledby="honesty-title">
      <h2 id="honesty-title" style={{ fontSize: "0.92rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
        Honesty constraints
      </h2>
      <ul
        style={{
          marginTop: "0.5rem",
          paddingLeft: "1.2rem",
          fontSize: "0.83rem",
          lineHeight: 1.55,
        }}
      >
        <li>
          <strong>Resolved:</strong> {manifest.counts.resolvedBinary} forecasts
          (binary YES/NO) — full weight in the metrics above.
        </li>
        <li>
          <strong>Stale, unresolved:</strong> {manifest.counts.staleUnresolved}{" "}
          forecasts published more than {manifest.publishHorizonDays} days
          ago and still pending. Flagged here, not silently dropped.
        </li>
        <li>
          <strong>Withdrawn / revoked:</strong> {manifest.counts.withdrawn}{" "}
          forecasts. Excluded from calibration metrics, but counted toward
          the published withdrawn rate of{" "}
          {manifest.withdrawnRate !== null
            ? `${(manifest.withdrawnRate * 100).toFixed(1)}%`
            : "—"}
          . Pulling a bad call back is not free.
        </li>
        <li>
          <strong>Sparse bins:</strong> bins with fewer than{" "}
          {manifest.sparseBinThreshold} resolved items are drawn open with
          their <code>n</code> labelled. We refuse to draw a CI we cannot
          defend.
        </li>
      </ul>
      {manifest.notes.length > 0 ? (
        <ul
          style={{
            marginTop: "0.6rem",
            paddingLeft: "1.2rem",
            fontSize: "0.78rem",
            color: "#5a5247",
          }}
        >
          {manifest.notes.map((note, i) => (
            <li key={i}>{note}</li>
          ))}
        </ul>
      ) : null}
    </section>
  );
}

function Deciles({ best, worst }: { best: DecileEntry[]; worst: DecileEntry[] }) {
  return (
    <section style={{ marginBottom: "2rem" }} aria-labelledby="deciles-title">
      <h2 id="deciles-title" style={{ fontSize: "0.92rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
        Best and worst calls
      </h2>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
          gap: "1rem",
          marginTop: "0.5rem",
        }}
      >
        <DecileColumn title="Top decile (lowest Brier)" entries={best} accent="#1f6f3a" />
        <DecileColumn title="Bottom decile (highest Brier)" entries={worst} accent="#a52a2a" />
      </div>
    </section>
  );
}

function DecileColumn({
  title,
  entries,
  accent,
}: {
  title: string;
  entries: DecileEntry[];
  accent: string;
}) {
  return (
    <div>
      <h3 style={{ fontSize: "0.78rem", letterSpacing: "0.16em", textTransform: "uppercase", color: accent }}>
        {title}
      </h3>
      {entries.length === 0 ? (
        <p style={{ fontSize: "0.82rem", color: "#7a6d55" }}>No entries match this filter.</p>
      ) : (
        <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
          {entries.map((e) => (
            <li
              key={e.predictionId}
              style={{ borderTop: "1px solid #ece8de", padding: "0.45rem 0", fontSize: "0.83rem" }}
            >
              <div style={{ display: "flex", justifyContent: "space-between", gap: "0.5rem" }}>
                <strong style={{ flex: 1, fontWeight: 500 }}>{e.headline || e.marketTitle}</strong>
                <span
                  style={{
                    fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
                    color: accent,
                  }}
                >
                  {e.brier.toFixed(3)}
                </span>
              </div>
              <div style={{ color: "#7a6d55", fontSize: "0.74rem", marginTop: "0.15rem" }}>
                p={e.probabilityYes.toFixed(3)} · resolved {e.outcome}
                {e.methodName ? (
                  <>
                    {" · "}
                    <Link
                      href={`/calibration?method=${encodeURIComponent(e.methodName)}${e.methodVersion ? `&version=${encodeURIComponent(e.methodVersion)}` : ""}`}
                      style={{ color: "#7a5b0d" }}
                    >
                      {e.methodName}
                    </Link>
                  </>
                ) : null}
                {e.marketUrl ? (
                  <>
                    {" · "}
                    <a href={e.marketUrl} rel="noreferrer" style={{ color: "#7a5b0d" }}>
                      market →
                    </a>
                  </>
                ) : null}
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

function Methods({
  manifest,
  active,
}: {
  manifest: PublicCalibrationManifest;
  active: CalibrationFilter;
}) {
  if (manifest.methods.length === 0) return null;
  return (
    <section style={{ marginBottom: "2rem" }} aria-labelledby="methods-title">
      <h2 id="methods-title" style={{ fontSize: "0.92rem", letterSpacing: "0.18em", textTransform: "uppercase" }}>
        Per-method drill-down
      </h2>
      <p style={{ fontSize: "0.82rem", color: "#5a5247", marginTop: "0.4rem" }}>
        Click a method to filter the scorecard to predictions linked through it. The
        method's full track record (calibration slope, severity gate,
        domain bounds) lives on the methodology pages.
      </p>
      <ul
        style={{
          listStyle: "none",
          padding: 0,
          marginTop: "0.5rem",
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
          gap: "0.5rem",
        }}
      >
        {manifest.methods.map((m) => {
          const isActive = active.methodName === m.name;
          const href = isActive
            ? "/calibration"
            : `/calibration?method=${encodeURIComponent(m.name)}&version=${encodeURIComponent(m.version)}`;
          return (
            <li
              key={`${m.name}@${m.version}`}
              style={{
                border: `1px solid ${isActive ? "#d4a017" : "#d8d4cb"}`,
                background: isActive ? "#fffbeb" : "#ffffff",
                padding: "0.6rem 0.8rem",
              }}
            >
              <Link
                href={href}
                style={{
                  textDecoration: "none",
                  color: "#3a342a",
                  fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
                  fontSize: "0.85rem",
                }}
              >
                {m.name}
              </Link>
              <div style={{ fontSize: "0.72rem", color: "#7a6d55", marginTop: "0.2rem" }}>
                v{m.version} · n={m.n} ·{" "}
                <Link
                  href={`/methodology/${encodeURIComponent(m.name)}/track-record`}
                  style={{ color: "#7a5b0d" }}
                >
                  full record →
                </Link>
              </div>
            </li>
          );
        })}
      </ul>
    </section>
  );
}

function ManifestPointer() {
  return (
    <section style={{ borderTop: "1px solid #ece8de", paddingTop: "1rem", color: "#5a5247", fontSize: "0.78rem" }}>
      <p style={{ margin: 0 }}>
        Auditors:{" "}
        <a
          href="/api/public/calibration/manifest"
          style={{ color: "#7a5b0d" }}
        >
          /api/public/calibration/manifest
        </a>{" "}
        returns the full data backing this page. The page renders only what the
        manifest contains; if the hash here doesn't match what you re-derive
        from the manifest's resolution set, that's a bug — please file it.
      </p>
    </section>
  );
}

function fmt(value: number | null | undefined, digits = 3): string {
  if (value === null || value === undefined || !Number.isFinite(value)) return "—";
  return value.toFixed(digits);
}

