93	/**
94	 * One source-context match for a claim: the upload it came from plus a
95	 * trimmed before/match/after triple so the UI can render the quote with
96	 * the claim portion highlighted. `match` is empty when the literal claim
97	 * text wasn't found in the upload — `before` then holds a leading
98	 * excerpt of the upload as best-effort context.
99	 */
100	type ClaimContext = {
101	  uploadId: string;
102	  uploadTitle: string;
103	  uploadCreatedAt: string;
104	  before: string;
105	  match: string;
106	  after: string;
107	};
108	
109	const CONTEXT_PAD = 320; // chars of context around the matched passage
110	const FALLBACK_LEAD = 600; // chars of upload head when no match found
111	
112	function normalizeWhitespace(s: string): string {
113	  return s.replace(/\s+/g, " ").trim();
114	}
115	
116	/**
117	 * Find the best location of `needle` (the claim text) in `haystack`
118	 * (the upload's textContent). Strategy:
119	 *   1. Whole-needle case-insensitive substring (the common case for
120	 *      heuristically-extracted claims, which are copied verbatim).
121	 *   2. Longest 8+-word window from the needle (paraphrased LLM claims
122	 *      sometimes only share a contiguous run of words with the source).
123	 * Returns offsets into the ORIGINAL haystack (not the normalised one)
124	 * or null when no reasonable match exists.
125	 */
126	function locateClaim(
127	  haystack: string,
128	  needle: string,
129	): { start: number; end: number } | null {
130	  if (!haystack || !needle) return null;
131	  const hayLower = haystack.toLowerCase();
132	  const cleanNeedle = normalizeWhitespace(needle).toLowerCase();
133	  if (!cleanNeedle) return null;
134	
135	  const direct = hayLower.indexOf(cleanNeedle);
136	  if (direct !== -1) {
137	    return { start: direct, end: direct + cleanNeedle.length };
138	  }
139	
140	  const words = cleanNeedle.split(" ").filter((w) => w.length > 0);
141	  if (words.length < 8) return null;
142	  // Try progressively shorter windows from the middle of the claim,
143	  // since the start often has hedges ("I think", "it seems") and the
144	  // end often has qualifiers that get rewritten.
145	  for (let size = words.length - 1; size >= 8; size--) {
146	    for (let start = 0; start + size <= words.length; start++) {
147	      const window = words.slice(start, start + size).join(" ");
148	      const at = hayLower.indexOf(window);
149	      if (at !== -1) {
150	        return { start: at, end: at + window.length };
151	      }
152	    }
153	  }
154	  return null;
155	}
