157	async function loadClaimContexts(
158	  organizationId: string,
159	  claimIds: string[],
160	  claimTexts: Record<string, string>,
161	): Promise<Record<string, ClaimContext[]>> {
162	  if (claimIds.length === 0) return {};
163	  const conclusions = await db.conclusion.findMany({
164	    where: { id: { in: claimIds }, organizationId },
165	    select: {
166	      id: true,
167	      sources: {
168	        select: {
169	          upload: {
170	            select: {
171	              id: true,
172	              title: true,
173	              textContent: true,
174	              createdAt: true,
175	              deletedAt: true,
176	            },
177	          },
178	        },
179	        // Two sources is plenty for context; more would just add noise
180	        // to the card.
181	        take: 2,
182	      },
183	    },
184	  });
185	
186	  const out: Record<string, ClaimContext[]> = {};
187	  for (const c of conclusions) {
188	    const claim = claimTexts[c.id] || "";
189	    const ctxs: ClaimContext[] = [];
190	    for (const s of c.sources) {
191	      const u = s.upload;
192	      if (!u || u.deletedAt) continue;
193	      const text = u.textContent || "";
194	      if (!text) continue;
195	      const hit = locateClaim(text, claim);
196	      if (hit) {
197	        const beforeStart = Math.max(0, hit.start - CONTEXT_PAD);
198	        const afterEnd = Math.min(text.length, hit.end + CONTEXT_PAD);
199	        ctxs.push({
200	          uploadId: u.id,
201	          uploadTitle: u.title,
202	          uploadCreatedAt: u.createdAt.toISOString(),
203	          before:
204	            (beforeStart > 0 ? "…" : "") + text.slice(beforeStart, hit.start),
205	          match: text.slice(hit.start, hit.end),
206	          after:
207	            text.slice(hit.end, afterEnd) + (afterEnd < text.length ? "…" : ""),
208	        });
209	      } else {
210	        ctxs.push({
211	          uploadId: u.id,
212	          uploadTitle: u.title,
213	          uploadCreatedAt: u.createdAt.toISOString(),
214	          before:
215	            text.slice(0, FALLBACK_LEAD) +
216	            (text.length > FALLBACK_LEAD ? "…" : ""),
217	          match: "",
218	          after: "",
219	        });
220	      }
221	      if (ctxs.length >= 2) break; // hard cap
222	    }
223	    if (ctxs.length > 0) out[c.id] = ctxs;
224	  }
225	  return out;
226	}
