    class Text(str):
        pass

# ── Setup ────────────────────────────────────────────────────────────────────

console = Console()

from noosphere.observability import configure_logging

configure_logging(level="WARNING", json_format=False)


# ── Utilities ────────────────────────────────────────────────────────────────

def parse_date(date_str: str) -> date:
    """Parse date string in YYYY-MM-DD format."""
    try:
        return datetime.strptime(date_str, "%Y-%m-%d").date()
    except ValueError:
        raise click.BadParameter(
            f"Invalid date format: {date_str}. Use YYYY-MM-DD"
        )

"""Plugin loader for CLI command modules.

Every Python module in this package that exposes a top-level Click group
named ``cli`` is automatically discovered and attached to the root CLI
group.
"""

from __future__ import annotations

import importlib
import pkgutil
import sys
import types
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    import click


def register_commands(root_cli: click.Group) -> None:
    """Import every sibling module and attach its ``cli`` group to *root_cli*."""
    _install_rich_fallback_if_needed()
    package = importlib.import_module(__name__)
    for _importer, modname, _ispkg in pkgutil.iter_modules(package.__path__):
        mod = importlib.import_module(f"{__name__}.{modname}")
        group = getattr(mod, "cli", None)
        if group is not None:
            root_cli.add_command(group)


def _install_rich_fallback_if_needed() -> None:
    try:
        import rich  # noqa: F401
        return
    except ImportError:
        pass

    class Console:
        def print(self, *args, **_kwargs) -> None:
            print(" ".join(str(arg) for arg in args))

    class Table:
        def __init__(self, title: str = "", show_header: bool = True, **_kwargs) -> None:
            self.title = title
            self.rows: list[tuple[str, ...]] = []

        def add_column(self, *_args, **_kwargs) -> None:
            return None

        def add_row(self, *args, **_kwargs) -> None:
            self.rows.append(tuple(str(arg) for arg in args))

        def __str__(self) -> str:
            lines = [self.title] if self.title else []
            lines.extend(" | ".join(row) for row in self.rows)
            return "\n".join(lines)

    rich_mod = types.ModuleType("rich")
    console_mod = types.ModuleType("rich.console")
    table_mod = types.ModuleType("rich.table")
    console_mod.Console = Console
    table_mod.Table = Table
    rich_mod.console = console_mod
    rich_mod.table = table_mod
    sys.modules.setdefault("rich", rich_mod)
    sys.modules.setdefault("rich.console", console_mod)
    sys.modules.setdefault("rich.table", table_mod)

"""CLI commands for the Evaluation (counterfactual analysis) subsystem."""

from __future__ import annotations

import json
from datetime import datetime, timedelta, timezone
from typing import Optional

import click
from rich.console import Console
from rich.table import Table

console = Console()


def _get_store():
    from noosphere.cli import get_orchestrator
    return get_orchestrator(None).store


def _parse_ts(val: Optional[str]) -> Optional[datetime]:
    if val is None:
        return None
    return datetime.fromisoformat(val).replace(tzinfo=timezone.utc)


@click.group("eval")
def cli() -> None:
    """Evaluation: counterfactual analysis and calibration metrics."""


@cli.group("counterfactual")
def counterfactual() -> None:
    """Counterfactual evaluation sub-commands."""


@counterfactual.command("run")
@click.option("--method", "method_ref", type=str, default=None,
              help="Method reference (name@version)")
@click.option("--since", type=str, default=None, help="Window start (ISO 8601)")
@click.option("--until", type=str, default=None, help="Window end (ISO 8601)")
@click.option("--cadence-days", type=int, default=7, help="Cadence in days")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def cf_run(method_ref: Optional[str], since: Optional[str],
           until: Optional[str], cadence_days: int, as_json: bool) -> None:
    """Run a counterfactual evaluation over a time window."""
    from noosphere.evaluation import CounterfactualRunner
    from noosphere.methods import REGISTRY
    from noosphere.models import MethodRef

    store = _get_store()
    if method_ref:
        name, version = (method_ref.split("@", 1) + ["latest"])[:2]
        _method, fn = REGISTRY.get(name, version=version)
        ref = MethodRef(name=name, version=version)
    else:
        methods = REGISTRY.list(status_filter="active")
        if not methods:
            console.print("[yellow]No active methods found.[/yellow]")
            raise SystemExit(1)
        m = methods[0]
        _method, fn = REGISTRY.get(m.name, version=m.version)
        ref = MethodRef(name=m.name, version=m.version)

    start = _parse_ts(since) or datetime.now(tz=timezone.utc) - timedelta(days=90)
    end = _parse_ts(until) or datetime.now(tz=timezone.utc)
    runner = CounterfactualRunner(store, fn, ref)
    run_result = runner.run(start, end, timedelta(days=cadence_days))
    if as_json:
        click.echo(json.dumps(run_result.model_dump(), indent=2, default=str))
        return
    table = Table(title=f"Counterfactual Run: {run_result.run_id[:12]}", show_header=False)
    table.add_row("Run ID", run_result.run_id)
    table.add_row("Method", f"{ref.name}@{ref.version}")
    table.add_row("Created", str(run_result.created_at))
    console.print(table)


@counterfactual.command("show")
@click.argument("run_id")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def cf_show(run_id: str, as_json: bool) -> None:
    """Show details of a counterfactual run."""
    store = _get_store()
    run_result = store.get_counterfactual_run(run_id)
    if run_result is None:
        console.print(f"[red]Run {run_id} not found.[/red]")
        raise SystemExit(1)
    if as_json:
        click.echo(json.dumps(run_result.model_dump(), indent=2, default=str))
        return
    table = Table(title=f"Run {run_id[:12]}", show_header=False)
    table.add_row("Run ID", run_result.run_id)
    table.add_row("Method", str(run_result.method_ref))
    table.add_row("Created", str(run_result.created_at))
    console.print(table)


@counterfactual.command("report")
@click.argument("run_id")
@click.option("--out-dir", type=click.Path(), default=None,
              help="Directory for rendered report artifacts")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def cf_report(run_id: str, out_dir: Optional[str], as_json: bool) -> None:
    """Render a human-readable report for a counterfactual run."""
    from pathlib import Path
    from noosphere.evaluation import render

    store = _get_store()
    run_result = store.get_counterfactual_run(run_id)
    if run_result is None:
        console.print(f"[red]Run {run_id} not found.[/red]")
        raise SystemExit(1)
    target = Path(out_dir) if out_dir else Path(".")
    paths = render(run_result, target)
    if as_json:
        click.echo(json.dumps({k: str(v) for k, v in paths.items()}, indent=2))
        return
    for label, p in paths.items():
        console.print(f"  {label}: {p}")
    console.print("[bold green]✓ Report rendered.[/bold green]")

class Conclusion(BaseModel):
    """A reasoned conclusion drawn from principles and claims."""

    id: str = Field(default_factory=lambda: str(uuid.uuid4()))
    text: str
    reasoning: str = ""
    rationale: str = ""
    kind: ConclusionKind = ConclusionKind.FIRM
    confidence_tier: ConfidenceTier = ConfidenceTier.MODERATE
    principles_used: list[str] = []
    claims_used: list[str] = []
    supporting_principle_ids: list[str] = Field(default_factory=list)
    evidence_chain_claim_ids: list[str] = Field(default_factory=list)
    dissent_claim_ids: list[str] = Field(default_factory=list)
    confidence: float = 0.0
    disciplines: list[Discipline] = []
    created_at: datetime = Field(default_factory=datetime.now)
    updated_at: datetime = Field(default_factory=datetime.now)
    superseded_at: Optional[datetime] = None
    # Round 3 additions
    freshness: Freshness = Freshness.FRESH
    last_validated_at: Optional[datetime] = None

    @model_validator(mode="after")
    def _sync_legacy_aliases(self) -> Conclusion:
        if not self.rationale and self.reasoning:
            self.rationale = self.reasoning
        if not self.reasoning and self.rationale:
            self.reasoning = self.rationale
        if not self.supporting_principle_ids and self.principles_used:
            self.supporting_principle_ids = list(self.principles_used)
        if not self.principles_used and self.supporting_principle_ids:
            self.principles_used = list(self.supporting_principle_ids)
        if not self.evidence_chain_claim_ids and self.claims_used:
            self.evidence_chain_claim_ids = list(self.claims_used)
        if not self.claims_used and self.evidence_chain_claim_ids:
            self.claims_used = list(self.evidence_chain_claim_ids)
        return self


SIGNIFICANCE_WEIGHTS: dict[str, float] = {
    "impressions": 0.4,
    "retweets": 0.3,
    "likes": 0.2,
    "replies": 0.05,
    "quotes_bookmarks": 0.1,
}
# These weights deliberately privilege impressions as reach, retweets as
# endorsement-led amplification, likes as broad reaction volume, replies as
# public conversational activity, and quotes/bookmarks as deeper engagement
# signals; the resulting log-sum is monotonic while dampening raw-count
# outliers until prompt 03 adds ranking.


def _metric_count(value: Any) -> int:
    if value is None:
        return 0
    try:
        number = float(value)
    except (TypeError, ValueError):
        return 0
    if not math.isfinite(number) or number < 0:
        return 0
    return int(number)


class XSignificanceMetrics(BaseModel):
